// Check if within business hours
const config = $node['get_bot_config'].json[0];
const hoursEnabled = config.business_hours_enabled;
const timezone = config.business_hours_timezone || 'UTC';
const startTime = config.business_hours_start;
const endTime = config.business_hours_end;
const afterHoursMsg = config.after_hours_message || 'Sorry, we\'re closed now. Please reach out during business hours.';

if (!hoursEnabled) {
  return { isBusinessHours: true };
}

// Simple hour check (simplified, real implementation would use timezone)
const now = new Date();
const currentHour = now.getHours();
const [startHour] = startTime.split(':').map(Number);
const [endHour] = endTime.split(':').map(Number);

const isWithinHours = currentHour >= startHour && currentHour < endHour;
return { isBusinessHours: isWithinHours, afterHoursMsg };

// Match incoming text against template triggers
const text = $node['workflow_trigger'].json.text.toLowerCase();
const templates = $node['get_templates'].json;

for (const template of templates) {
  const keywords = JSON.parse(template.trigger_keywords);
  const matched = keywords.some(keyword => text.includes(keyword.toLowerCase()));

  if (matched) {
    return {
      templateMatched: true,
      templateId: template.id,
      responseText: template.response_text,
      priority: template.priority
    };
  }
}

return { templateMatched: false };

